// 1. Hacemos la petición a la API de la UNLP
const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://gestionapp.info.unlp.edu.ar/api/CALENDARIO_ACADEMICO',
    json: true
});

// 2. Función para limpiar HTML (quita tags y espacios extra)
function cleanHtml(text) {
    if (!text) return '';
    // Reemplaza cualquier tag HTML (<...>) por un salto de línea
    let clean = text.replace(/<[^>]+>/g, '\n');
    // Reemplaza múltiples espacios/saltos por uno solo
    clean = clean.replace(/\s+/g, ' ').trim();
    return clean;
}

// 3. Procesamos los datos para reducir tamaño
const cleanData = response.map(item => {
    return {
        calendario: item.nombre,
        contenido: cleanHtml(item.contenido)
    };
});

// 4. 🔥 CORRECCIÓN: Convertimos el objeto a TEXTO (String) para que el Agente lo entienda
return JSON.stringify(cleanData);

// 1. LA HERRAMIENTA HACE SU PROPIA PETICIÓN (Autónoma)
// Esto asegura que los datos siempre estén disponibles cuando el Agente llame a la Tool
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestiondocente.info.unlp.edu.ar/api/v2/materias.json',
  json: true
});

// 2. EXTRAER EL ARRAY DE MATERIAS DEL RESULTADO
const materias = response._embedded?.materias || [];

// 3. EXTRAER SOLO LOS NOMBRES, LIMPIAR Y ELIMINAR DUPLICADOS
const nombresUnicos = [...new Set(materias.map(m => m.nombre ? m.nombre.trim() : ""))].filter(n => n !== "");

// 4. ORDENAR ALFABÉTICAMENTE
nombresUnicos.sort((a, b) => a.localeCompare(b));

// 5. VALIDACIÓN
if (nombresUnicos.length === 0) {
    return "No se pudo obtener la lista de materias en este momento.";
}

// 6. RETORNAR EL STRING PLANO
// El Agente recibirá esto y Groq decidirá qué mostrar según la pregunta del usuario
return "LISTADO COMPLETO DE MATERIAS:\n" + nombresUnicos.join('\n');

// 1. OBTENER EL PARÁMETRO DE BÚSQUEDA
// El agente nos envía esto gracias al Schema que definimos arriba.
const busqueda = (query.carrera || "").toLowerCase().trim();

if (!busqueda) {
    return "⚠️ Error: Debes especificar una carrera para buscar el plan de estudios.";
}

// 2. PETICIÓN AL ENDPOINT (Trae todos los planes)
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestionapp.info.unlp.edu.ar/api/PLANES_ESTUDIOS',
  json: true
});

const todosLosPlanes = Array.isArray(response) ? response : (response.planes || []);

// 3. FILTRADO INTELIGENTE
// Buscamos coincidencias (ej: si busca "sistemas", trae "Lic. en Sistemas 2015" y "Lic. en Sistemas 2021")
const planesEncontrados = todosLosPlanes.filter(p => {
    const nombrePlan = (p.nombre || "").toLowerCase();
    // Normalizamos para ignorar tildes en la búsqueda
    const nombreNormalizado = nombrePlan.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    const busquedaNormalizada = busqueda.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    return nombreNormalizado.includes(busquedaNormalizada);
});

// Si no encuentra nada, devolvemos la lista de nombres disponibles para ayudar al agente
if (planesEncontrados.length === 0) {
    const nombresDisponibles = todosLosPlanes.map(p => `- ${p.nombre}`).join("\n");
    return `❌ No encontré ningún plan que coincida con "${query.carrera}".\n\nLos planes disponibles son:\n${nombresDisponibles}`;
}

// 4. LIMPIEZA DE DATOS (Solo de los encontrados)
const resultadoLimpio = planesEncontrados.map(p => {
    let contenido = (p.contenido || "")
        // Borrar atributos de estilo y clases (Lo que más ocupa)
        .replace(/ (style|class|width|height|border|cellpadding|cellspacing|align|valign|rel|target)="[^"]*"/gi, '')
        // Borrar spans, divs, strong, b, u, a (dejando el texto)
        .replace(/<\/?(span|div|p|strong|b|u|a|h5)[^>]*>/gi, ' ')
        // Limpieza de espacios y saltos de línea
        .replace(/&nbsp;/g, ' ')
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/\s+/g, ' ')
        .trim();

    return {
        carrera: p.nombre,
        plan_estudio: contenido // Esto contiene la <table> limpia
    };
});

// 5. RETORNO SEGURO
return JSON.stringify(resultadoLimpio);

